// Extraire les données du webhook
const body = $input.item.json.body || $input.item.json;
const question = body.question || '';

console.log('📥 Données reçues:', {
  question_length: question.length,
  has_tables: question.includes('<table>'),
  timestamp: new Date().toISOString()
});

// Compter les tables
const tableCount = (question.match(/<table/g) || []).length;

// Retourner les données pour traitement
return {
  json: {
    question: question,
    tableCount: tableCount,
    receivedAt: new Date().toISOString(),
    size: question.length
  }
};

// Simuler un traitement
const data = $input.item.json;

// Créer une réponse formatée
const response = {
  success: true,
  message: 'Données reçues et traitées avec succès',
  data: {
    tables_received: data.tableCount,
    size_kb: (data.size / 1024).toFixed(2),
    processed_at: new Date().toISOString()
  },
  // Exemple de réponse HTML (vous pouvez personnaliser)
  html_response: `<div style="padding: 20px; background: #f0f0f0; border-radius: 8px;">
    <h2>✅ Traitement Réussi</h2>
    <p><strong>Tables reçues:</strong> ${data.tableCount}</p>
    <p><strong>Taille:</strong> ${(data.size / 1024).toFixed(2)} KB</p>
    <p><strong>Traité à:</strong> ${new Date().toLocaleString('fr-FR')}</p>
  </div>`
};

console.log('✅ Réponse préparée:', response);

return { json: response };
